import * as Select from '@radix-ui/react-select';

const mono = "'JetBrains Mono', monospace";
const ui = "'Plus Jakarta Sans', sans-serif";

// Radix Select.Item forbids value="". Use a sentinel for "clear/all" options.
const EMPTY_SENTINEL = '__aura_all__';

export default function AuraSelect({ options = [], value, onChange, placeholder = 'Select...', label }) {
  // Map external empty-string value to the internal sentinel
  const internalValue = value === '' || value == null ? EMPTY_SENTINEL : value;

  const handleChange = (v) => {
    onChange(v === EMPTY_SENTINEL ? '' : v);
  };

  // Filter out any options whose value resolves to an empty string and remap
  const safeOptions = options
    .map(opt => {
      const raw = typeof opt === 'string' ? opt : opt.value;
      const lbl = typeof opt === 'string' ? opt : opt.label;
      return { value: raw === '' ? EMPTY_SENTINEL : raw, label: lbl };
    })
    .filter(opt => opt.value); // drop any remaining falsy values

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
      {label && (
        <span style={{ fontSize: 11, color: '#8B949E', fontFamily: ui, textTransform: 'uppercase', letterSpacing: '0.06em', fontWeight: 600 }}>
          {label}
        </span>
      )}
      <Select.Root value={internalValue} onValueChange={handleChange}>
        <Select.Trigger
          style={{
            display: 'inline-flex', alignItems: 'center', justifyContent: 'space-between', gap: 8,
            padding: '8px 12px', minWidth: 160, borderRadius: 10,
            background: 'rgba(15,22,32,0.65)', backdropFilter: 'blur(12px)',
            border: '1px solid #30363D', color: '#E6EDF3', fontSize: 13,
            fontFamily: mono, cursor: 'pointer', outline: 'none',
            transition: 'border-color 0.25s',
          }}
          onFocus={e => { e.currentTarget.style.borderColor = '#60A5FA'; }}
          onBlur={e => { e.currentTarget.style.borderColor = '#30363D'; }}
        >
          <Select.Value placeholder={placeholder} />
          <Select.Icon>
            <svg width="12" height="12" viewBox="0 0 12 12" fill="none" stroke="#8B949E" strokeWidth="1.5" strokeLinecap="round">
              <path d="M3 4.5L6 7.5L9 4.5" />
            </svg>
          </Select.Icon>
        </Select.Trigger>

        <Select.Portal>
          <Select.Content
            position="popper"
            sideOffset={4}
            style={{
              background: '#161B22', border: '1px solid #30363D', borderRadius: 10,
              boxShadow: '0 12px 40px rgba(0,0,0,0.5)', overflow: 'hidden',
              minWidth: 'var(--radix-select-trigger-width)', zIndex: 200,
              maxHeight: 320,
            }}
          >
            <Select.Viewport style={{ padding: 4 }}>
              {safeOptions.map(opt => (
                  <Select.Item
                    key={opt.value}
                    value={opt.value}
                    style={{
                      padding: '8px 12px', borderRadius: 6, fontSize: 13,
                      fontFamily: mono, color: '#E6EDF3', cursor: 'pointer',
                      outline: 'none', transition: 'background 0.15s',
                    }}
                    onMouseEnter={e => { e.currentTarget.style.background = '#1C2128'; }}
                    onMouseLeave={e => { e.currentTarget.style.background = 'transparent'; }}
                  >
                    <Select.ItemText>{opt.label}</Select.ItemText>
                  </Select.Item>
                ))}
            </Select.Viewport>
          </Select.Content>
        </Select.Portal>
      </Select.Root>
    </div>
  );
}
