import { useState, useEffect, useCallback } from 'react';
import { Link, useLocation } from 'react-router-dom';
import AnimatedPage from '../components/AnimatedPage';
import MetricCard from '../components/MetricCard';
import SortableFilterTable from '../components/SortableFilterTable';
import AuraSelect from '../components/AuraSelect';
import { api } from '../utils/api';
import s from './ResearchDashboardPage.module.css';

const RESEARCH_TABS = [
  { label: 'Dashboard', path: '/research' },
  { label: 'Regime', path: '/research/regime' },
  { label: 'Promotions', path: '/research/promotions' },
  { label: 'Portfolio', path: '/research/portfolio' },
  { label: 'Sweep', path: '/research/sweep' },
];

export function ResearchSubNav() {
  const location = useLocation();
  return (
    <div className={s.subNav}>
      {RESEARCH_TABS.map(tab => {
        const active = location.pathname === tab.path;
        return (
          <Link
            key={tab.path}
            to={tab.path}
            className={`${s.subNavLink} ${active ? s.subNavLinkActive : ''}`}
          >
            {tab.label}
          </Link>
        );
      })}
    </div>
  );
}

const STRATEGY_COLS = [
  { key: 'strategy_id', label: 'Strategy', width: 180, mono: false, filterType: 'text', filterable: true },
  { key: 'fitness_score', label: 'Fitness', width: 90, align: 'right', filterType: 'range', filterable: true },
  { key: 'profit_factor', label: 'PF', width: 70, align: 'right', render: v => (v != null ? Number(v).toFixed(2) : '--') },
  { key: 'win_rate', label: 'WR%', width: 70, align: 'right', render: v => (v != null ? `${Number(v).toFixed(1)}%` : '--') },
  { key: 'trade_count', label: 'Trades', width: 80, align: 'right' },
  { key: 'pnl', label: 'PnL', width: 100, align: 'right', render: v => {
    if (v == null) return '--';
    const n = Number(v);
    return <span className={n >= 0 ? s.pnlPositive : s.pnlNegative}>${n.toFixed(0)}</span>;
  }},
  { key: 'drawdown', label: 'DD%', width: 70, align: 'right', render: v => (v != null ? `${Number(v).toFixed(1)}%` : '--') },
  { key: 'recommendation_stage', label: 'Stage', width: 100, filterType: 'select', filterable: true },
];

const FAMILY_COLS = [
  { key: 'Family', label: 'Family', width: 160, mono: false },
  { key: 'Avg Fitness', label: 'Avg Fitness', width: 120, align: 'right' },
  { key: 'Best Fitness', label: 'Best Fitness', width: 120, align: 'right' },
];

export default function ResearchDashboardPage() {
  const [latest, setLatest] = useState(null);
  const [strategies, setStrategies] = useState(null);
  const [status, setStatus] = useState(null);
  const [familyFilter, setFamilyFilter] = useState('');
  const [loading, setLoading] = useState(true);

  const fetchData = useCallback(async () => {
    const [latestRes, stratRes, statusRes] = await Promise.all([
      api('/research/latest'),
      api('/research/strategies?limit=200'),
      api('/research/status'),
    ]);
    setLatest(latestRes);
    setStrategies(stratRes);
    setStatus(statusRes);
    setLoading(false);
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  // Auto-poll when sweep is running
  useEffect(() => {
    if (!status || status.status === 'complete' || status.status === 'idle') return;
    const iv = setInterval(async () => {
      const s = await api('/research/status');
      setStatus(s);
      if (s?.status === 'complete') fetchData();
    }, 5000);
    return () => clearInterval(iv);
  }, [status, fetchData]);

  const isRunning = status && status.status !== 'complete' && status.status !== 'idle';
  const families = latest?.top_families || [];
  const strats = strategies?.strategies || [];

  // Filter strategies by family
  const filteredStrats = familyFilter
    ? strats.filter(s => (s.strategy_id || '').toLowerCase().includes(familyFilter.toLowerCase()))
    : strats;

  // Extract unique families from strategy IDs
  const familyOptions = [{ value: '', label: 'All Families' }];
  const seen = new Set();
  strats.forEach(s => {
    const parts = (s.strategy_id || '').split('_');
    const fam = parts[0];
    if (fam && !seen.has(fam)) { seen.add(fam); familyOptions.push({ value: fam, label: fam }); }
  });

  return (
    <AnimatedPage>
      <div className={s.page}>
        <ResearchSubNav />

        <h1 className={s.pageTitle}>Research Dashboard</h1>

        {/* Progress bar when running */}
        {isRunning && (
          <div className={s.progressCard}>
            <div className={s.progressHeader}>
              <span className={s.progressStage}>
                Sweep Running: {status.stage}
              </span>
              <span className={s.progressMeta}>
                {status.cases_done}/{status.cases_total} cases ({status.pct}%)
              </span>
            </div>
            <div className={s.progressTrack}>
              <div className={s.progressFill} style={{ width: `${status.pct}%` }} />
            </div>
          </div>
        )}

        {/* Metric cards */}
        <div className={s.metricsRow}>
          <MetricCard label="Cases Tested" value={latest?.total_cases ?? '--'} />
          <MetricCard label="Monday Confidence" value={latest?.monday_confidence ? `${latest.monday_confidence}/5` : '--'} />
          <MetricCard label="Top Fitness" value={latest?.top_10_fitness?.[0]?.fitness?.toFixed(1) ?? '--'} />
          <MetricCard label="Elapsed" value={latest?.elapsed_sec ? `${latest.elapsed_sec.toFixed(0)}s` : '--'} />
        </div>

        {/* Run info bar */}
        {latest && !latest.error && (
          <div className={s.runInfoBar}>
            {[
              ['Run', latest.run_id],
              ['Scope', latest.scope],
              ['Region', latest.region?.toUpperCase()],
              ['Regime', latest.current_regime],
              ['Strategies', latest.unique_strategies],
            ].map(([k, v]) => (
              <div key={k} className={s.runInfoItem}>
                <span className={s.runInfoLabel}>{k}: </span>
                <span className={s.runInfoValue}>{v ?? '--'}</span>
              </div>
            ))}
          </div>
        )}

        {/* Top Families table */}
        {families.length > 0 && (
          <div className={s.familySection}>
            <h2 className={s.sectionTitle}>Top Families</h2>
            <SortableFilterTable
              columns={FAMILY_COLS}
              data={families}
              loading={loading}
              defaultSortKey="Avg Fitness"
              defaultSortDir="desc"
              emptyMessage="No family data"
            />
          </div>
        )}

        {/* Strategy table with filters */}
        <div className={s.strategySection}>
          <div className={s.strategySectionHeader}>
            <h2 className={s.sectionTitleNoMargin}>
              Top Strategies ({filteredStrats.length})
            </h2>
            <AuraSelect
              options={familyOptions}
              value={familyFilter}
              onChange={setFamilyFilter}
              placeholder="Filter by family"
            />
          </div>
          <SortableFilterTable
            columns={STRATEGY_COLS}
            data={filteredStrats.slice(0, 50)}
            loading={loading}
            defaultSortKey="fitness_score"
            defaultSortDir="desc"
            emptyMessage="No strategies found"
          />
        </div>

        {/* Link cards to sub-pages */}
        <div className={s.linkGrid}>
          {RESEARCH_TABS.filter(t => t.path !== '/research').map(tab => (
            <Link key={tab.path} to={tab.path} className={s.linkCard}>
              <div className={s.linkCardTitle}>{tab.label}</div>
              <div className={s.linkCardSub}>View details</div>
            </Link>
          ))}
        </div>
      </div>
    </AnimatedPage>
  );
}
