import T, { fonts } from '../tokens';
import InfoTooltip, { getDefinition } from './InfoTooltip';
import { useState } from 'react';

export default function MetricCard({ label, value, change, color = T.textPrimary, icon }) {
  const [hovered, setHovered] = useState(false);

  const changeColor = change > 0 ? T.green : change < 0 ? T.red : T.textSecondary;

  let accentBackground = 'linear-gradient(135deg, #36BDF0, #A78BFA)';
  if (change > 0) {
    accentBackground = 'linear-gradient(135deg, #22C55E, #36BDF0)';
  } else if (change < 0) {
    accentBackground = 'linear-gradient(135deg, #EF4444, #FB7185)';
  }

  return (
    <div
      style={{
        position: 'relative',
        padding: '16px 18px',
        borderRadius: 14,
        background: 'rgba(15,22,32,0.65)',
        backdropFilter: 'blur(12px) saturate(1.2)',
        border: hovered ? '1px solid rgba(54,189,240,0.15)' : '1px solid rgba(255,255,255,0.06)',
        flex: 1,
        minWidth: 160,
        boxShadow: hovered
          ? 'inset 0 1px 0 0 rgba(255,255,255,0.04), 0 0 12px 3px rgba(54,189,240,0.5)'
          : 'inset 0 1px 0 0 rgba(255,255,255,0.04), 0 8px 32px rgba(0,0,0,0.2)',
        transition: 'border-color 0.25s ease, box-shadow 0.25s ease',
      }}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
      <div
        style={{
          position: 'absolute',
          top: 0,
          left: 12,
          right: 12,
          height: 2,
          width: 'calc(100% - 24px)',
          margin: '0 auto',
          borderRadius: '0 0 2px 2px',
          background: accentBackground,
        }}
      />
      <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}>
        {icon && <span style={{ fontSize: 14 }}>{icon}</span>}
        <span
          style={{
            fontSize: 11,
            color: '#90A3AF',
            fontWeight: 500,
            textTransform: 'uppercase',
            letterSpacing: '0.06em',
            fontFamily: fonts.ui,
          }}
        >
          {label}
        </span>
        {getDefinition(label) && <InfoTooltip term={label} size={12} />}
      </div>
      <div
        style={{
          fontSize: 22,
          fontWeight: 700,
          color,
          fontFamily: "'JetBrains Mono', monospace",
          fontVariantNumeric: 'tabular-nums',
        }}
      >
        {value}
      </div>
      {change != null && (
        <div
          style={{
            fontSize: 11,
            color: changeColor,
            marginTop: 4,
            fontFamily: "'JetBrains Mono', monospace",
            fontVariantNumeric: 'tabular-nums',
            fontWeight: 700,
          }}
        >
          {change >= 0 ? '+' : ''}
          {typeof change === 'number' ? change.toFixed(2) : change}
        </div>
      )}
    </div>
  );
}